const CACHE_NAME='portfolio-cache-v1';const ASSETS=['./','./index.html','./style.css','./portfolio.min.js','./model-v1.glb','./select.wav','./icons/robotica-icon.avif','./icons/software-icon.avif','./icons/iot-icon.avif','./img/measly543.jpg','./img/acercademi.avif'];self.addEventListener('install',e=>{e.waitUntil(caches.open(CACHE_NAME).then(c=>c.addAll(ASSETS)).then(()=>self.skipWaiting()))});self.addEventListener('activate',e=>{e.waitUntil(caches.keys().then(ks=>Promise.all(ks.map(k=>{if(k!==CACHE_NAME)return caches.delete(k)}))).then(()=>self.clients.claim()))});self.addEventListener('fetch',e=>{const u=new URL(e.request.url);if(u.origin!==self.location.origin){if(u.hostname.includes('googleapis.com')||u.hostname.includes('gstatic.com')||u.hostname.includes('cdnjs.cloudflare.com')||u.hostname.includes('unpkg.com')){e.respondWith(caches.open('external-cache').then(c=>c.match(e.request).then(cr=>{const fr=fetch(e.request).then(nr=>{c.put(e.request,nr.clone());return nr}).catch(()=>null);return cr||fr})))}return}e.respondWith(caches.match(e.request).then(cr=>{if(cr){if(e.request.url.endsWith('.html')||e.request.url.endsWith('.css')||e.request.url.endsWith('.js')||e.request.url===self.location.origin+'/'||e.request.url===self.location.origin+'/index.html'){fetch(e.request).then(nr=>{if(nr.status===200)caches.open(CACHE_NAME).then(c=>c.put(e.request,nr))}).catch(()=>{})}return cr}return fetch(e.request).then(nr=>{if(!nr||nr.status!==200||nr.type!=='basic')return nr;const rc=nr.clone();caches.open(CACHE_NAME).then(c=>c.put(e.request,rc));return nr})}))});
